  const { q, lat, lng, radius_km, category } = req.query;

  const searchParams = {
    q: q || '*',
    query_by: 'name,description',
    typo_tokens_threshold: 1,       // typo-tolerant ranking
    num_typos: 2,                   // allow up to 2 typos
    filter_by: buildFilters({ lat, lng, radius_km, category }),
    sort_by: lat && lng
      ? `location(${lat}, ${lng}):asc`
      : '_text_match:desc',
    per_page: 20
  };

  try {
    const results = await client
      .collections('products')
      .documents()
      .search(searchParams);

    res.json(results);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

function buildFilters({ lat, lng, radius_km, category }) {
  const filters = [];

  if (lat && lng && radius_km) {
    filters.push(`location:(${lat}, ${lng}, ${radius_km} km)`);
  }

  if (category) {
    filters.push(`category:=${category}`);
  }

  return filters.join(' && ');
}
```

